    pub fn handle_ticker(&self, mut client: Value, mut message: Value) {
        //
        // market/snapshot
        //
        // updates come in every 2 sec unless there
        // were no changes since the previous update
        //
        //     {
        //         "data": {
        //             "sequence": "1545896669291",
        //             "data": {
        //                 "trading": true,
        //                 "symbol": "KCS-BTC",
        //                 "buy": 0.00011,
        //                 "sell": 0.00012,
        //                 "sort": 100,
        //                 "volValue": 3.13851792584, // total
        //                 "baseCurrency": "KCS",
        //                 "market": "BTC",
        //                 "quoteCurrency": "BTC",
        //                 "symbolCode": "KCS-BTC",
        //                 "datetime": 1548388122031,
        //                 "high": 0.00013,
        //                 "vol": 27514.34842,
        //                 "low": 0.0001,
        //                 "changePrice": -1.0e-5,
        //                 "changeRate": -0.0769,
        //                 "lastTradedPrice": 0.00012,
        //                 "board": 0,
        //                 "mark": 0
        //             }
        //         },
        //         "subject": "trade.snapshot",
        //         "topic": "/market/snapshot:KCS-BTC",
        //         "type": "message"
        //     }
        //
        // market/ticker
        //
        //     {
        //         "type": "message",
        //         "topic": "/market/ticker:BTC-USDT",
        //         "subject": "trade.ticker",
        //         "data": {
        //             "bestAsk": "62163",
        //             "bestAskSize": "0.99011388",
        //             "bestBid": "62162.9",
        //             "bestBidSize": "0.04794181",
        //             "price": "62162.9",
        //             "sequence": "1621383371852",
        //             "size": "0.00832274",
        //             "time": 1634641987564
        //         }
        //     }
        //
        // futures
        //    {
        //     "subject": "ticker",
        //     "topic": "/contractMarket/ticker:XBTUSDM",
        //     "data": {
        //         "symbol": "XBTUSDM", //Market of the symbol
        //         "sequence": 45, //Sequence number which is used to judge the continuity of the pushed messages
        //         "side": "sell", //Transaction side of the last traded taker order
        //         "price": "3600.0", //Filled price
        //         "size": 16, //Filled quantity
        //         "tradeId": "5c9dcf4170744d6f5a3d32fb", //Order ID
        //         "bestBidSize": 795, //Best bid size
        //         "bestBidPrice": "3200.0", //Best bid
        //         "bestAskPrice": "3600.0", //Best ask size
        //         "bestAskSize": 284, //Best ask
        //         "ts": 1553846081210004941 //Filled time - nanosecond
        //     }
        //    }
        //
        let mut topic: Value = self.safe_string_k(message.clone(), "topic", &[]);
        if is_less_than(&get_index_of(&topic, &Value::Str("contractMarket".to_string())), &Value::Int(0)) {
            let mut market: Value = Value::Null;
            if !is_equal(&topic, &Value::Null) {
                let mut parts: Value = split(&topic, &Value::Str(":".to_string()));
                let mut first: Value = self.safe_string(parts.clone(), Value::Int(1), &[]);
                let mut marketId: Value = Value::Null;
                if is_equal(&first, &Value::Str("all".to_string())) {
                    marketId = self.safe_string_k(message.clone(), "subject", &[]);
                }  else {
                    marketId = first.clone();
                }
                market = self.safe_market(&[marketId.clone(), market.clone(), Value::Str("-".to_string())]);
            }
            let mut data: Value = self.safe_dict_k(message.clone(), "data", &[Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            })]);
            let mut rawTicker: Value = self.safe_dict_k(data.clone(), "data", &[data.clone()]);
            let mut ticker: Value = self.parse_spot_or_uta_ticker(rawTicker.clone(), &[market.clone()]);
            let mut symbol: Value = get_value(&ticker, &Value::Str("symbol".to_string()));
            add_element_to_object(&mut self.tickers.clone(), &symbol, ticker.clone());
            let mut messageHash: Value = add(&Value::Str("ticker:".to_string()), &symbol);
            client.resolve(&[ticker.clone(), messageHash.clone()]);
            // watchTickers
            let mut allTickers: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            });
            add_element_to_object(&mut allTickers, &symbol, ticker.clone());
            client.resolve(&[allTickers.clone(), Value::Str("tickers".to_string())]);
        }  else {
            self.handle_contract_ticker(client.clone(), message.clone());
        }
}

    pub fn handle_contract_ticker(&self, mut client: Value, mut message: Value) {
        //
        // ticker (v1)
        //
        //    {
        //     "subject": "ticker",
        //     "topic": "/contractMarket/ticker:XBTUSDM",
        //     "data": {
        //         "symbol": "XBTUSDM", //Market of the symbol
        //         "sequence": 45, //Sequence number which is used to judge the continuity of the pushed messages
        //         "side": "sell", //Transaction side of the last traded taker order
        //         "price": "3600.0", //Filled price
        //         "size": 16, //Filled quantity
        //         "tradeId": "5c9dcf4170744d6f5a3d32fb", //Order ID
        //         "bestBidSize": 795, //Best bid size
        //         "bestBidPrice": "3200.0", //Best bid
        //         "bestAskPrice": "3600.0", //Best ask size
        //         "bestAskSize": 284, //Best ask
        //         "ts": 1553846081210004941 //Filled time - nanosecond
        //     }
        //    }
        //
        let mut data: Value = self.safe_dict_k(message.clone(), "data", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut marketId: Value = self.safe_string_k(data.clone(), "symbol", &[]);
        let mut market: Value = self.safe_market(&[marketId.clone(), Value::Null, Value::Str("-".to_string())]);
        let mut ticker: Value = self.parse_ticker(data.clone(), &[market.clone()]);
        add_element_to_object(&mut self.tickers.clone(), &get_value(&market, &Value::Str("symbol".to_string())), ticker.clone());
        let mut messageHash: Value = add(&Value::Str("ticker:".to_string()), &get_value(&market, &Value::Str("symbol".to_string())));
        client.resolve(&[ticker.clone(), messageHash.clone()]);
}

    pub fn handle_uta_ticker(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "T": "ticker.SPOT",
        //         "P": "1774100940787520626",
        //         "d": {
        //             "A": "0.5972689",
        //             "B": "23.3114947",
        //             "E": 20310552932,
        //             "M": "1774100940780000000",
        //             "S": "SELL",
        //             "a": "2155.55",
        //             "b": "2155.54",
        //             "l": "2155.54",
        //             "q": "0.0001529",
        //             "s": "ETH-USDT"
        //         }
        //     }
        //
        let mut data: Value = self.safe_dict_k(message.clone(), "d", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut marketId: Value = self.safe_string_k(data.clone(), "s", &[]);
        let mut market: Value = self.safe_market(&[marketId.clone()]);
        let mut ticker: Value = self.parse_ws_uta_ticker(data.clone(), &[market.clone()]);
        add_element_to_object(&mut self.tickers.clone(), &get_value(&market, &Value::Str("symbol".to_string())), ticker.clone());
        let mut messageHash: Value = add(&Value::Str("uta:ticker:".to_string()), &get_value(&market, &Value::Str("symbol".to_string())));
        client.resolve(&[ticker.clone(), messageHash.clone()]);
}

    pub fn parse_ws_uta_ticker(&self, mut ticker: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        let mut symbol: Value = self.safe_string_k(market.clone(), "symbol", &[]);
        market = self.safe_market(&[symbol.clone(), market.clone()]);
        let mut timestamp: Value = self.safe_integer_product(ticker.clone(), Value::Str("M".to_string()), Value::Float(0.000001), &[]);
        return self.safe_ticker(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("high".to_string(), Value::Null);
        m.insert("low".to_string(), Value::Null);
        m.insert("bid".to_string(), self.safe_string_k(ticker.clone(), "a", &[]));
        m.insert("bidVolume".to_string(), self.safe_string_k(ticker.clone(), "A", &[]));
        m.insert("ask".to_string(), self.safe_string_k(ticker.clone(), "b", &[]));
        m.insert("askVolume".to_string(), self.safe_string_k(ticker.clone(), "B", &[]));
        m.insert("vwap".to_string(), Value::Null);
        m.insert("open".to_string(), Value::Null);
        m.insert("close".to_string(), Value::Null);
        m.insert("last".to_string(), self.safe_string_k(ticker.clone(), "l", &[]));
        m.insert("previousClose".to_string(), Value::Null);
        m.insert("change".to_string(), Value::Null);
        m.insert("percentage".to_string(), Value::Null);
        m.insert("average".to_string(), Value::Null);
        m.insert("baseVolume".to_string(), Value::Null);
        m.insert("quoteVolume".to_string(), Value::Null);
        m.insert("markPrice".to_string(), Value::Null);
        m.insert("info".to_string(), ticker.clone());
    m
}), &[market.clone()]);

    Value::Null
}

